import React from 'react';
import './Footer.css';

export default function Footer({ hero }) {
  return (
    <footer className="footer">
      <div className="footer-left">
        <span className="footer-logo">{hero?.name || 'RajaGanesh'}</span>
        <span className="footer-tagline">{hero?.title || 'App Developer & Java Developer'}</span>
      </div>
      <span className="footer-center">B.E CSE - DSEC Perambalur - 2023 to 2027</span>
      <span className="footer-right">Built with React and Node.js</span>
    </footer>
  );
}
